class Solution {
public:
    int smallestValue(int n) {
        int res = n;
        while (true) {
            int sum = 1;
            for (int i = 2; i * i <= n; i++) {
                while (n % i == 0) {
                    sum += i;
                    n /= i;
                }
            }
            if (n > 1) {
                sum += n;
            }
            if (sum == res) {
                break;
            }
            res = sum;
        }
        return res;
    }
};
